body:
### Version

Yosys 0.33 (git sha1 2584903a0, gcc 12.2.0-14 -Og -O3 -DNDEBUG -fPIC)

### On which OS did this happen?

Linux

### Reproduction Steps


crashtest.tcl
```tcl
yosys -import

set WAY  2
set WIRE 32

set NAME "Dlatch"

read_verilog $NAME.v
chparam -set "WAY" $WAY $NAME
chparam -set "WIRE" $WIRE $NAME

#segfault inside
hierarchy -check -top $NAME
check

write_verilog out.v
write_spice out.sp
write_rtlil out.rtlil
```

Dlatch.v
 ```verilog
 `ifndef __DLATCH__
 `define __DLATCH__

 `include "parallel_Dlatch.v"
 `include "serial_Dlatch.v"

module Dlatch (D, clk, Q, QN);
   parameter WAY = 1;
   parameter WIRE = 1;

   input [WAY -1: 0] clk;
   input [(WAY * WIRE)-1 : 0] D;
   output [(WAY * WIRE)-1:0]  Q, QN;

   wire [4:0] line;

   if (WAY > 1)
        parallel_Dlatch #(.WAY(WAY), .WIRE(WIRE)) parallel_Dlatch_inst(D, clk, Q, QN);
   else if (WIRE > 1)
        serial_Dlatch #(.WIRE(WIRE)) inst0(a, clk, s1, s2);
   else
     begin
        not not0(line[0], D);

        and and0(line[1], line[0], clk);
        and and1(line[2], D      , clk);

        nor nor0(line[3], line[1], line[4]);
        nor nor1(line[4], line[2], line[3]);

        assign Q  = line[3];
        assign QN = line[4];
     end

endmodule

`endif
 ```
 
parallel_Dlatch.v
 ```verilog
 `ifndef __PARALLEL_DLATCH__
 `define __PARALLEL_DLATCH__

`include "Dlatch.v"
`include "serial_Dlatch.v"

module parallel_Dlatch(D, clk, Q, QN);
   parameter WAY = 3;
   parameter WIRE = 8;

   input [WAY-1:0] clk;
   input [(WAY*WIRE)-1 : 0] D;
   output [(WAY*WIRE)-1 : 0] Q, QN;

   if (WIRE == 1)
     Dlatch Dlatch0(D[0], clk[0], Q[0], QN[0]);
   else if (WIRE > 1)
     serial_Dlatch #(.WIRE(WIRE)) Dlatch1(D[WIRE-1:0], clk[0], Q[WIRE-1:0], QN[WIRE-1:0]);

   if (WAY > 1)
     parallel_Dlatch #(.WAY(WAY-1), .WIRE(WIRE)) parallel_Dlatch0(D[WAY*WIRE-1 : WIRE],
                                                                  clk[WAY-1:1],
                                                                  Q[WAY*WIRE-1 : WIRE],
                                                                  QN[WAY*WIRE-1 : WIRE]);
endmodule

`endif

 ```
 
